/**
 * @fileoverview Shared ResizeObserver pool.
 *
 * Instead of each component creating its own `new ResizeObserver(...)`,
 * a single browser-level observer is reused. Components register
 * per-element callbacks via `observe(el, cb)` and clean up with
 * `unobserve(el)`.
 *
 * For components that observe multiple elements (e.g. GridTable),
 * a **scope** can be created — it tracks all observed elements so
 * `scope.disconnect()` unobserves them all at once, mirroring the
 * native `ResizeObserver.disconnect()` API.
 *
 * @module shared/SharedResizeObserver
 *
 * @example
 *   import { sharedResizeObserver } from './SharedResizeObserver.js';
 *
 *   // Simple: one element
 *   sharedResizeObserver.observe(el, (entry) => { … });
 *   sharedResizeObserver.unobserve(el);
 *
 *   // Scoped: multiple elements with bulk disconnect
 *   const scope = sharedResizeObserver.createScope();
 *   scope.observe(wrapper, (entry) => { … });
 *   scope.observe(viewport, (entry) => { … });
 *   scope.disconnect();   // unobserves wrapper + viewport
 */

// ── Singleton pool ──────────────────────────

/** @type {Map<Element, Function>} */
const callbacks = new Map();

/** @type {ResizeObserver|null} */
let observer = null;

/**
 * Lazily create the single shared ResizeObserver.
 * @returns {ResizeObserver}
 */
function getObserver() {
    if (!observer) {
        observer = new ResizeObserver((entries) => {
            for (const entry of entries) {
                const cb = callbacks.get(entry.target);
                if (cb) cb(entry);
            }
        });
    }
    return observer;
}

// ── Public API ──────────────────────────────

/**
 * Start observing an element. If the element is already observed,
 * its callback is replaced (last-write-wins).
 *
 * @param {Element} el       — DOM element to observe
 * @param {Function} callback — called with the `ResizeObserverEntry`
 */
function observe(el, callback) {
    callbacks.set(el, callback);
    getObserver().observe(el);
}

/**
 * Stop observing an element and remove its callback.
 *
 * @param {Element} el — DOM element to stop observing
 */
function unobserve(el) {
    callbacks.delete(el);
    getObserver().unobserve(el);
}

/**
 * Create a scoped handle that tracks multiple observations and
 * can disconnect them all at once. Ideal for components that
 * observe several elements during their lifecycle.
 *
 * @returns {ObserverScope}
 *
 * @typedef {Object} ObserverScope
 * @property {function(Element, Function): void} observe
 *     Observe an element with a callback (also tracked by scope).
 * @property {function(Element): void} unobserve
 *     Stop observing a single element.
 * @property {function(): void} disconnect
 *     Stop observing ALL elements tracked by this scope.
 * @property {number} size
 *     Number of elements currently tracked.
 */
function createScope() {
    /** @type {Set<Element>} */
    const tracked = new Set();

    return {
        observe(el, callback) {
            tracked.add(el);
            observe(el, callback);
        },

        unobserve(el) {
            tracked.delete(el);
            unobserve(el);
        },

        disconnect() {
            for (const el of tracked) unobserve(el);
            tracked.clear();
        },

        get size() {
            return tracked.size;
        },
    };
}

/**
 * The number of elements currently being observed across all scopes.
 * Useful for testing and diagnostics.
 *
 * @returns {number}
 */
function getActiveCount() {
    return callbacks.size;
}

// ── Singleton export ────────────────────────

export const sharedResizeObserver = {
    observe,
    unobserve,
    createScope,
    getActiveCount,
};
